// COOP/COEP Service Worker for SharedArrayBuffer support on GitHub Pages
//
// The _headers file (generated by deploy-pages.yml) adds COOP+COEP+CORP to
// ALL responses. This should be sufficient for crossOriginIsolated=true.
//
// The SW is only needed as a FALLBACK for the first page load (before the
// SW is active). Once the SW is active, the _headers file handles everything.
//
// For /deps/ requests: add CORP (sync XHR can read this)
// For ALL other requests: pass through (let _headers file handle it)

const CACHE_NAME = 'sdv-coop-coep-v11';

self.addEventListener('install', (event) => {
    self.skipWaiting();
});

self.addEventListener('activate', (event) => {
    event.waitUntil(self.clients.claim());
});

self.addEventListener('fetch', (event) => {
    const req = event.request;

    if (req.method !== 'GET' || !req.url.startsWith(self.location.origin)) {
        return;
    }

    if (req.cache === 'only-if-cached' && req.mode !== 'same-origin') {
        return;
    }

    // For /deps/ requests: add ONLY CORP header (sync XHR needs it)
    // The _headers file should also add CORP, but we keep this as fallback
    // in case the _headers file doesn't cover /deps/ paths.
    if (req.url.includes('/deps/')) {
        const newHeaders = new Headers();
        newHeaders.set('Cross-Origin-Resource-Policy', 'cross-origin');
        event.respondWith(
            fetch(req).then((response) => {
                if (response.status === 0) return response;
                const h = new Headers(response.headers);
                h.set('Cross-Origin-Resource-Policy', 'cross-origin');
                return new Response(response.body, {
                    status: response.status,
                    statusText: response.statusText,
                    headers: h,
                });
            })
        );
        return;
    }

    // For ALL other requests: let the browser handle natively.
    // The _headers file (deployed by GitHub Pages) adds COOP+COEP+CORP
    // to all responses. SW interception of large _framework/*.wasm files
    // caused "Failed to fetch" errors, so we skip them entirely.
    return;
});
